     9→namespace Envoy {
    10→namespace Extensions {
    11→namespace AccessLoggers {
    12→
    13→template <class T, Filesystem::DestinationType destination_type>
    14→AccessLog::InstanceSharedPtr
    15→createStreamAccessLogInstance(const Protobuf::Message& config, AccessLog::FilterPtr&& filter,
    16→                              Server::Configuration::FactoryContext& context) {
    17→  const auto& fal_config =
    18→      MessageUtil::downcastAndValidate<const T&>(config, context.messageValidationVisitor());
    19→  Formatter::FormatterPtr formatter;
    20→  if (fal_config.access_log_format_case() == T::AccessLogFormatCase::kLogFormat) {
    21→    formatter =
    22→        Formatter::SubstitutionFormatStringUtils::fromProtoConfig(fal_config.log_format(), context);
    23→  } else if (fal_config.access_log_format_case() ==
    24→             T::AccessLogFormatCase::ACCESS_LOG_FORMAT_NOT_SET) {
    25→    formatter = Formatter::HttpSubstitutionFormatUtils::defaultSubstitutionFormatter();
    26→  }
    27→  Filesystem::FilePathAndType file_info{destination_type, ""};
    28→  return std::make_shared<AccessLoggers::File::FileAccessLog>(
    29→      file_info, std::move(filter), std::move(formatter),
    30→      context.serverFactoryContext().accessLogManager());
    31→}
